mapper.select:
WITH AUTH_PROJECT AS ( SELECT p.project_code, p.project_name FROM projects p WHERE EXISTS ( SELECT 1 FROM VW_USER_PROJECT_AUTH v WHERE v.user_code = #{userCode} AND v.project_code = p.project_code ) ),
FOLDER_TREE AS ( SELECT f.folder_code, f.project_code, f.folder_name, LEVEL AS folder_depth, SYS_CONNECT_BY_PATH(f.folder_name, '/') AS folder_path, SYS_CONNECT_BY_PATH(LPAD(f.folder_code, 10, '0'), '/') AS sort_path FROM documents_folders f START WITH f.header_folder_code IS NULL CONNECT BY PRIOR f.folder_code = f.header_folder_code )
SELECT * FROM (
/* 1️⃣ 프로젝트 */ SELECT NULL AS file_code, NULL AS original_name, NULL AS size_bytes, NULL AS uploaded_at, NULL AS mime_type, NULL AS folder_code, ap.project_code, ap.project_name, NULL AS uploaderName, NULL AS folder_path, 0 AS folder_depth, NULL AS folder_name, TO_CHAR(ap.project_code, 'FM0000000000') AS sort_path, 'PROJECT' AS row_type FROM AUTH_PROJECT ap
UNION ALL
/* 2️⃣ 폴더 */ SELECT NULL, NULL, NULL, NULL, NULL, ft.folder_code, ft.project_code, ap.project_name, NULL, ft.folder_path, ft.folder_depth, ft.folder_name, TO_CHAR(ft.project_code, 'FM0000000000') || ft.sort_path, 'FOLDER' FROM FOLDER_TREE ft JOIN AUTH_PROJECT ap ON ft.project_code = ap.project_code
UNION ALL
/* 3️⃣ 파일 */ SELECT da.file_code, da.original_name, da.size_bytes, da.uploaded_at, da.mime_type, da.folder_code, da.project_code, ap.project_name, u.name AS uploaderName, ft.folder_path, ft.folder_depth, ft.folder_name, TO_CHAR(da.project_code, 'FM0000000000') || ft.sort_path || '/' || LPAD(da.file_code, 10, '0'), 'FILE' FROM documents_attachments da JOIN AUTH_PROJECT ap ON da.project_code = ap.project_code LEFT JOIN users u ON da.user_code = u.user_code LEFT JOIN FOLDER_TREE ft ON da.folder_code = ft.folder_code
) t ORDER BY t.sort_path, DECODE(t.row_type, 'PROJECT', 1, 'FOLDER', 2, 'FILE', 3)

SELECT COUNT(*)
FROM documents_folders
WHERE header_folder_code = #{folderCode}
